#!/usr/bin/env Rscript

suppressPackageStartupMessages({library(Seurat);library(SeuratObject);library(spacexr);library(Matrix);library(data.table);library(jsonlite);library(ggplot2)})
parse_args<-function(x){o<-list();i<-1L;while(i<=length(x)){k<-sub("^--","",x[i]);if(i==length(x)||startsWith(x[i+1],"--")){o[[k]]<-TRUE;i<-i+1L}else{o[[k]]<-x[i+1];i<-i+2L}};o};a<-parse_args(commandArgs(trailingOnly=TRUE));need<-c("rds","query-membership","reference-membership","out","cell-id-col","reference-label-col");miss<-need[!need%in%names(a)];if(length(miss))stop("Missing: ",paste(miss,collapse=", "))
read_any<-function(p)if(grepl("\\.gz$",p))fread(cmd=paste("gzip -dc",shQuote(p)))else fread(p);dir.create(a$out,recursive=TRUE,showWarnings=FALSE);dir.create(file.path(a$out,"tables"),showWarnings=FALSE);dir.create(file.path(a$out,"objects"),showWarnings=FALSE);dir.create(file.path(a$out,"figures"),showWarnings=FALSE);dir.create(file.path(a$out,"provenance"),showWarnings=FALSE)
seed<-as.integer(ifelse(is.null(a$seed),20260713,a$seed));set.seed(seed);cores<-as.integer(ifelse(is.null(a$cores),16,a$cores));max_ref<-as.integer(ifelse(is.null(a$`max-reference-per-label`),1200,a$`max-reference-per-label`));val_per<-as.integer(ifelse(is.null(a$`validation-per-label`),200,a$`validation-per-label`));min_precision<-as.numeric(ifelse(is.null(a$`min-validation-precision`),0.90,a$`min-validation-precision`));min_model_accuracy<-as.numeric(ifelse(is.null(a$`min-model-accuracy`),0.85,a$`min-model-accuracy`));min_validation_calls<-as.integer(ifelse(is.null(a$`min-validation-calls`),30,a$`min-validation-calls`));cc<-a$`cell-id-col`;lc<-a$`reference-label-col`
thin_sparse<-function(x,targets){x<-as(x,"dgCMatrix");tot<-colSums(x);pr<-pmin(1,targets/pmax(tot,1));y<-x;for(j in seq_len(ncol(y))){lo<-y@p[j]+1L;hi<-y@p[j+1L];if(lo<=hi&&pr[j]<1)y@x[lo:hi]<-rbinom(hi-lo+1L,round(y@x[lo:hi]),pr[j])};drop0(y)}
extract_result<-function(fit,ids,truth=NULL){rdf<-tryCatch(as.data.table(as.data.frame(fit@results$results_df),keep.rownames="cell_id"),error=function(e)data.table());wm<-tryCatch(fit@results$weights,error=function(e)NULL);if(is.null(wm))wm<-tryCatch(fit@results$weights_doublet,error=function(e)NULL);if(!is.null(wm)){w<-as.matrix(wm);wdt<-as.data.table(w,keep.rownames="cell_id");cols<-setdiff(names(wdt),"cell_id");m<-as.matrix(wdt[,..cols]);i1<-max.col(m,ties.method="first");m2<-m;m2[cbind(seq_len(nrow(m2)),i1)]<--Inf;i2<-max.col(m2,ties.method="first");wdt[,`:=`(weight_top_label=cols[i1],top_weight=m[cbind(seq_len(nrow(m)),i1)],weight_margin=m[cbind(seq_len(nrow(m)),i1)]-m[cbind(seq_len(nrow(m)),i2)])];rdf<-merge(rdf,wdt[,.(cell_id,weight_top_label,top_weight,weight_margin)],by="cell_id",all.x=TRUE,sort=FALSE)};out<-merge(data.table(cell_id=ids),rdf,by="cell_id",all.x=TRUE,sort=FALSE);if(!"spot_class"%in%names(out))out[,spot_class:="filtered_by_RCTD"]else out[is.na(spot_class),spot_class:="filtered_by_RCTD"];if(!is.null(truth))out[,truth:=truth[cell_id]];out}
run_fit<-function(puck_counts,puck_xy,ref_counts,ref_labels,params){ref<-Reference(ref_counts,factor(ref_labels[colnames(ref_counts)]),setNames(as.integer(colSums(ref_counts)),colnames(ref_counts)));sp<-SpatialRNA(as.data.frame(puck_xy),puck_counts,setNames(as.integer(colSums(puck_counts)),colnames(puck_counts)));fit<-create.RCTD(sp,ref,max_cores=cores,test_mode=FALSE,UMI_min=as.integer(params$UMI_min),counts_MIN=as.integer(params$counts_MIN),UMI_min_sigma=as.integer(params$UMI_min_sigma),keep_reference=TRUE);run.RCTD(fit,doublet_mode="doublet")}
obj<-readRDS(a$rds);qmem<-read_any(a$`query-membership`);rmem<-read_any(a$`reference-membership`);qmem[[cc]]<-as.character(qmem[[cc]]);rmem[[cc]]<-as.character(rmem[[cc]]);if("query_or_anchor"%in%names(rmem))rmem<-rmem[query_or_anchor=="anchor"];if(uniqueN(qmem[[cc]])!=nrow(qmem)||uniqueN(rmem[[cc]])!=nrow(rmem)||any(qmem[[cc]]%in%rmem[[cc]]))stop("invalid query/reference boundary");if(!lc%in%names(rmem)||any(!nzchar(as.character(rmem[[lc]]))))stop("reference labels missing")
assay<-ifelse(is.null(a$assay),DefaultAssay(obj),a$assay);cts<-tryCatch(LayerData(obj[[assay]],layer="counts"),error=function(e)GetAssayData(obj[[assay]],slot="counts"));qids<-intersect(qmem[[cc]],colnames(obj));rids<-intersect(rmem[[cc]],colnames(obj));if(length(qids)!=nrow(qmem)||length(rids)!=nrow(rmem))stop("membership IDs missing from RDS");rmeta<-rmem[match(rids,get(cc))];rmeta[,rctd_type:=as.character(get(lc))]
sampled<-rmeta[,{
 nval<-min(val_per,max(20L,floor(.N*0.20)));nref<-min(max_ref,.N-nval);idx<-sample.int(.N,nval+nref);data.table(cell_id=get(cc)[idx],split=c(rep("validation",nval),rep("reference",nref)))
},by=rctd_type];if(any(sampled[,uniqueN(split),by=rctd_type]$V1<2))stop("each reference type requires reference and validation cells");fwrite(sampled[, .N,by=.(rctd_type,split)],file.path(a$out,"tables","anchor_split_counts.tsv"),sep="\t")
allids<-unique(c(qids,sampled$cell_id));genes<-rownames(cts);exclude<-grepl("^(LOC|KEF53|ENSOARG|RPL|RPS|MRPL|MRPS|MT[-_.])",genes,ignore.case=TRUE);det_min<-max(5L,as.integer(ceiling(length(allids)*0.0001)));genes_use<-genes[!exclude & Matrix::rowSums(cts[,allids,drop=FALSE]>0)>=det_min];if(length(genes_use)<500)stop("fewer than 500 usable genes");fwrite(data.table(gene=genes_use),file.path(a$out,"tables","feature_genes.tsv"),sep="\t")
md_names<-colnames(obj@meta.data);if(!is.null(a$`x-col`)||!is.null(a$`y-col`)){if(is.null(a$`x-col`)||is.null(a$`y-col`))stop("--x-col and --y-col must be supplied together");xy_cols<-c(a$`x-col`,a$`y-col`)}else{xy_candidates<-list(c("x","y"),c("sdimx","sdimy"),c("imagecol","imagerow"),c("col","row"));xy_hits<-vapply(xy_candidates,function(z)all(z%in%md_names),logical(1));if(!any(xy_hits))stop("spatial coordinate columns absent");xy_cols<-xy_candidates[[which(xy_hits)[1]]]};if(!all(xy_cols%in%md_names))stop("spatial coordinate columns absent");xy<-as.matrix(obj@meta.data[,xy_cols]);rownames(xy)<-colnames(obj);qcts<-as(cts[genes_use,qids,drop=FALSE],"dgCMatrix");refmeta<-sampled[split=="reference"];valmeta<-sampled[split=="validation"];refcts<-as(cts[genes_use,refmeta$cell_id,drop=FALSE],"dgCMatrix");val0<-as(cts[genes_use,valmeta$cell_id,drop=FALSE],"dgCMatrix");qpos<-as.numeric(colSums(qcts));qpos<-qpos[qpos>0];if(!length(qpos))stop("query has no positive counts");params<-list(conservative=list(UMI_min=max(20L,floor(quantile(qpos,.10))),counts_MIN=max(3L,floor(quantile(qpos,.01)/25)),UMI_min_sigma=max(50L,floor(median(qpos)))),adaptive=list(UMI_min=max(10L,floor(quantile(qpos,.01))),counts_MIN=max(2L,floor(quantile(qpos,.01)/40)),UMI_min_sigma=max(25L,floor(quantile(qpos,.25)))))
param_dt<-rbindlist(lapply(names(params),function(n){z<-as.data.table(params[[n]]);z[,parameterization:=n];z}),fill=TRUE);param_dt[,`:=`(query_umi_q01=quantile(qpos,.01),query_umi_q10=quantile(qpos,.10),query_umi_q25=quantile(qpos,.25),query_umi_median=median(qpos))];fwrite(param_dt,file.path(a$out,"tables","parameter_candidates.tsv"),sep="\t")
targets<-sample(qpos,ncol(val0),replace=TRUE);valcts<-thin_sparse(val0,targets);truth<-setNames(valmeta$rctd_type,valmeta$cell_id);rtruth<-setNames(refmeta$rctd_type,refmeta$cell_id);vals<-list();audit<-list()
for(nm in names(params)){fit<-run_fit(valcts,xy[colnames(valcts),,drop=FALSE],refcts,rtruth,params[[nm]]);rr<-extract_result(fit,colnames(valcts),truth);rr[,parameterization:=nm];vals[[nm]]<-rr;called<-rr$spot_class=="singlet" & !is.na(rr$first_type);audit[[nm]]<-data.table(parameterization=nm,validation_n=nrow(rr),returned_n=sum(rr$spot_class!="filtered_by_RCTD"),singlet_n=sum(called),singlet_coverage=mean(called),singlet_accuracy=if(sum(called))mean(rr$first_type[called]==rr$truth[called])else NA_real_,overall_accuracy=mean(rr$first_type==rr$truth,na.rm=TRUE));saveRDS(fit,file.path(a$out,"objects",paste0("validation_",nm,".rds")),compress=FALSE)}
vall<-rbindlist(vals,fill=TRUE);aud<-rbindlist(audit);aud[,utility:=singlet_accuracy*singlet_coverage];fwrite(vall,file.path(a$out,"tables","validation_cell_results.tsv.gz"),sep="\t");fwrite(aud,file.path(a$out,"tables","parameter_validation.tsv"),sep="\t");eligible<-aud[is.finite(singlet_accuracy)&singlet_accuracy>=min_model_accuracy&singlet_n>=min_validation_calls];if(nrow(eligible)){setorder(eligible,-utility,-singlet_accuracy);sel<-eligible$parameterization[1]}else{setorder(aud,-singlet_accuracy,-singlet_coverage);sel<-aud$parameterization[1]}
v<-vall[parameterization==sel & spot_class=="singlet" & is.finite(top_weight)&is.finite(weight_margin)];grid<-CJ(min_top_weight=unique(as.numeric(quantile(v$top_weight,seq(0,.9,.05),na.rm=TRUE))),min_weight_margin=unique(as.numeric(quantile(v$weight_margin,seq(0,.9,.05),na.rm=TRUE))));grid[,`:=`(validation_n=0L,validation_precision=NA_real_,validation_recall=NA_real_)];for(i in seq_len(nrow(grid))){k<-v$top_weight>=grid$min_top_weight[i]&v$weight_margin>=grid$min_weight_margin[i];grid$validation_n[i]<-sum(k);if(sum(k))grid$validation_precision[i]<-mean(v$first_type[k]==v$truth[k]);grid$validation_recall[i]<-sum(k&v$first_type==v$truth)/max(1,sum(v$first_type==v$truth))}
select_threshold<-function(target_precision,min_calls,lower=NULL){z<-grid[validation_n>=min_calls&validation_precision>=target_precision];if(!is.null(lower))z<-z[min_top_weight>=lower$min_top_weight&min_weight_margin>=lower$min_weight_margin];if(nrow(z)){setorder(z,-validation_n,-validation_precision,-validation_recall);z[1]}else data.table(min_top_weight=Inf,min_weight_margin=Inf,validation_n=0L,validation_precision=NA_real_,validation_recall=0)}
high_thr<-select_threshold(min_precision,min_validation_calls);applicable<-is.finite(high_thr$min_top_weight);extreme_precision<-as.numeric(ifelse(is.null(a$`extreme-validation-precision`),max(0.98,min_precision),a$`extreme-validation-precision`));extreme_min_calls<-as.integer(ifelse(is.null(a$`extreme-min-validation-calls`),max(10L,floor(min_validation_calls/3)),a$`extreme-min-validation-calls`));extreme_thr<-if(applicable)select_threshold(extreme_precision,extreme_min_calls,high_thr)else data.table(min_top_weight=Inf,min_weight_margin=Inf,validation_n=0L,validation_precision=NA_real_,validation_recall=0)
fwrite(grid,file.path(a$out,"tables","threshold_grid.tsv"),sep="\t");policy<-rbindlist(list(cbind(data.table(tier="high",parameterization=sel,applicable=applicable,target_precision=min_precision,min_model_accuracy=min_model_accuracy),high_thr),cbind(data.table(tier="extreme",parameterization=sel,applicable=is.finite(extreme_thr$min_top_weight),target_precision=extreme_precision,min_model_accuracy=min_model_accuracy),extreme_thr)),fill=TRUE);fwrite(policy,file.path(a$out,"tables","selected_policy.tsv"),sep="\t")
fit<-run_fit(qcts,xy[qids,,drop=FALSE],refcts,rtruth,params[[sel]]);saveRDS(fit,file.path(a$out,"objects","query_rctd.rds"),compress=FALSE);query<-extract_result(fit,qids);base_singlet<-applicable&query$spot_class=="singlet"&query$weight_top_label==query$first_type&is.finite(query$top_weight)&is.finite(query$weight_margin);high_pass<-base_singlet&query$top_weight>=high_thr$min_top_weight&query$weight_margin>=high_thr$min_weight_margin;extreme_pass<-base_singlet&query$top_weight>=extreme_thr$min_top_weight&query$weight_margin>=extreme_thr$min_weight_margin;query[,rctd_confidence_tier:="medium_low"];query[high_pass,rctd_confidence_tier:="high"];query[extreme_pass,rctd_confidence_tier:="extreme"];query[,validated_singlet:=rctd_confidence_tier%in%c("extreme","high")];query[,`:=`(proposed_broad_class=ifelse(validated_singlet,as.character(first_type),NA_character_),rctd_action=fifelse(rctd_confidence_tier=="extreme","extreme_candidate_independent_review",fifelse(rctd_confidence_tier=="high","high_candidate_broad_review","route_to_qc_holdout")),fine_anchor_eligible=FALSE,x=xy[cell_id,1],y=xy[cell_id,2])];fwrite(query,file.path(a$out,"tables","query_cell_adjudication.tsv.gz"),sep="\t");fwrite(query[, .N,by=.(spot_class,first_type,rctd_confidence_tier,validated_singlet,proposed_broad_class,rctd_action)][order(-N)],file.path(a$out,"tables","query_summary.tsv"),sep="\t");fwrite(query[rctd_confidence_tier=="medium_low",.(cell_id,first_type,weight_top_label,top_weight,weight_margin,rctd_confidence_tier,rctd_action)],file.path(a$out,"tables","rctd_qc_holdout_reroute_membership.tsv.gz"),sep="\t")
pal<-c(extreme_candidate_independent_review="#1B9E77",high_candidate_broad_review="#2CA02C",route_to_qc_holdout="#999999");pp<-ggplot(query,aes(x,y,colour=rctd_action))+geom_point(size=.15)+scale_colour_manual(values=pal)+scale_y_reverse()+coord_equal()+theme_void()+labs(title="Tiered low-priority RCTD evidence",colour=NULL);ggsave(file.path(a$out,"figures","rctd_adjudication.png"),pp,width=9,height=8,dpi=360,bg="white");ggsave(file.path(a$out,"figures","rctd_adjudication.pdf"),pp,width=9,height=8,device=cairo_pdf,bg="white")
tier_counts<-as.list(table(factor(query$rctd_confidence_tier,levels=c("extreme","high","medium_low"))));manifest<-list(status=if(applicable)"CALIBRATED_TIERED_EVIDENCE_ONLY" else "NOT_APPLICABLE_REVIEWED",n_query=length(qids),n_reference=nrow(refmeta),n_validation=nrow(valmeta),reference_types=as.list(table(refmeta$rctd_type)),feature_genes=length(genes_use),spatial_coordinate_columns=xy_cols,selected_parameterization=sel,selected_parameters=params[[sel]],best_validation_accuracy=max(aud$singlet_accuracy,na.rm=TRUE),applicable=applicable,high_policy=as.list(high_thr),extreme_policy=as.list(extreme_thr),rctd_extreme_n=tier_counts$extreme,rctd_high_n=tier_counts$high,rctd_medium_low_n=tier_counts$medium_low,thresholds_derived_from_heldout_query_depth_matched_anchors=TRUE,query_depth_matched_heldout_validation=TRUE,qc_holdout_reroute_membership=file.path(a$out,"tables","rctd_qc_holdout_reroute_membership.tsv.gz"),successor_state="qc_holdout",fine_anchor_eligible=FALSE,warning="RCTD is low-priority evidence only: extreme requires independent fine evidence; high is broad-only; every medium/low observation enters the frozen QC holdout and may reach Atlas only if it remains residual QC after complete QC-anchor reclustering.");write_json(manifest,file.path(a$out,"provenance","manifest.json"),pretty=TRUE,auto_unbox=TRUE);capture.output(sessionInfo(),file=file.path(a$out,"provenance","sessionInfo.txt"));writeLines(c("status\tPASS",paste0("completed_at\t",format(Sys.time(),tz="UTC",usetz=TRUE))),file.path(a$out,"RUN_COMPLETE.tsv"));quit(save="no",status=0,runLast=FALSE)
